    def __init__(self, requests=None):
        self._requests = []
        for request in requests or []:
            self.add_request(request)

    @property
    def requests(self):
        return tuple(self._requests)

    def add_request(self, request):
        if not isinstance(request, PantryRequest):
            raise TypeError("request must implement PantryRequest")
        self._requests.append(request)

    def mark_fulfilled(self, household):
        for request in self._requests:
            if request.household == household:
                request.mark_fulfilled()
                return True
        return False

    def count_open_requests(self):
        return sum(request.is_open() for request in self._requests)

    def summary_lines(self):
        return [request.summary() for request in self._requests]

