import csv

from models.food_request import FoodRequest
from models.hygiene_request import HygieneRequest


def parse_fulfilled(value):
    return str(value).strip().lower() in {"true", "1", "yes"}


def load_requests(path):
    requests = []
    with open(path, newline="", encoding="utf-8") as handle:
        for row in csv.DictReader(handle):
            common = {
                "household": row["household"],
                "priority": row["priority"],
                "fulfilled": parse_fulfilled(row["fulfilled"]),
            }
            if row["type"] == "food":
                request = FoodRequest(
                    food_type=row["detail"],
                    **common,
                )
            elif row["type"] == "hygiene":
                request = HygieneRequest(
                    units=int(row["detail"]),
                    **common,
                )
            else:
                raise ValueError(f"unknown request type: {row['type']}")
            requests.append(request)
    return requests

