    def __init__(self, household, priority="medium", fulfilled=False):
        self.household = household
        self.priority = priority
        self._fulfilled = bool(fulfilled)

    @property
    def household(self):
        return self._household

    @household.setter
    def household(self, value):
        cleaned = str(value).strip()
        if not cleaned:
            raise ValueError("household is required")
        self._household = cleaned

    @property
    def priority(self):
        return self._priority

    @priority.setter
    def priority(self, value):
        cleaned = str(value).strip().lower()
        if cleaned not in self.VALID_PRIORITIES:
            raise ValueError("invalid priority")
        self._priority = cleaned

    @property
    def fulfilled(self):
        return self._fulfilled

    def mark_fulfilled(self):
        self._fulfilled = True

    def is_open(self):
        return not self.fulfilled

    @property
    @abstractmethod
    def category(self):
        """Return the request category label."""

    @abstractmethod
    def details(self):
        """Return the subclass-specific detail text."""

    def summary(self):
        return (
            f"{self.category}: {self.household} | "
            f"priority={self.priority} | {self.details()} | "
            f"fulfilled={self.fulfilled}"
        )

